package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Peixe; public class Traira extends Peixe implements Nado, Predacao { public Traira(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " não emite som perceptível."); } public void comer() { System.out.println(getNome() + " está comendo pequenos peixes."); } public void nadar() { System.out.println(getNome() + " está nadando em água doce."); } public void cacar() { System.out.println(getNome() + " está emboscando a presa na vegetação."); } }
